import zipfile
from lxml import etree
W='http://schemas.openxmlformats.org/wordprocessingml/2006/main'
with zipfile.ZipFile('output/settlement-agreement-markup.docx') as z:
    xml = z.read('word/document.xml')
root = etree.fromstring(xml)
body = root.find(f'{{{W}}}body')
def render(p):
    parts=[]
    for child in p:
        tg=child.tag.split('}')[-1]
        if tg=='r':
            t=child.find(f'{{{W}}}t')
            if t is not None and t.text:
                parts.append(t.text)
        elif tg=='ins':
            txt=''.join(t.text or '' for t in child.iter(f'{{{W}}}t'))
            parts.append(' [[INS]]'+txt+'[[/INS]] ')
        elif tg=='del':
            txt=''.join(t.text or '' for t in child.iter(f'{{{W}}}delText'))
            parts.append(' [[DEL]]'+txt+'[[/DEL]] ')
    return ''.join(parts)
paras=body.findall(f'{{{W}}}p')
for i,p in enumerate(paras):
    r=render(p)
    if '[[INS]]' in r or '[[DEL]]' in r:
        print(f'=== P{i} ===')
        print(r[:600])
        print()
" 2>&1 | head -120"}

