import zipfile
from lxml import etree
W='http://schemas.openxmlformats.org/wordprocessingml/2006/main'
with zipfile.ZipFile('output/settlement-agreement-markup.docx') as z:
    xml = z.read('word/document.xml')
root = etree.fromstring(xml)
body = root.find(f'{{{W}}}body')
def accepted(p):
    # text = kept runs + ins runs; exclude del
    parts=[]
    for child in p.iter():
        tg=child.tag.split('}')[-1]
        if tg=='del' and child.get(f'{{{W}}}author'):
            # skip its delText
            continue
    # walk top-level
    out=[]
    for el in p:
        tg=el.tag.split('}')[-1]
        if tg=='r':
            t=el.find(f'{{{W}}}t')
            if t is not None and t.text: out.append(t.text)
        elif tg=='ins':
            out.append(''.join(t.text or '' for t in el.iter(f'{{{W}}}t')))
        elif tg=='del':
            pass
    return ''.join(out)
paras=body.findall(f'{{{W}}}p')
for i in [4,24,37,38,41,62,66,88,90,97,104,108,114,120]:
    print(f'--- P{i} (accepted) ---')
    print(accepted(paras[i])[:500])
    print()
""}

